create table dirkspzm32.s_pzm_pers (
    firma_nr        number(2, 0) not null enable,
    username        varchar2(50 char),
    passwort        varchar2(20 char),
    pers_nr         number(*, 0),
    anrede          varchar2(20 char),
    nname           varchar2(255 char),
    vname           varchar2(255 char),
    anschrift       varchar2(255 char),
    plz             number(5, 0),
    wohnort         varchar2(255 char),
    telefon_nr      varchar2(50 char),
    kuerzel         varchar2(5 char),
    geb_datum       date,
    staatsangeh     varchar2(50 char),
    geschlecht      varchar2(1 char),
    fam_stand       number(2, 0),
    behind_status   number(3, 0) default 0,
    kst             number(6, 0),
    urlaubstage     number(3, 0),
    taetigkeit      varchar2(100 char),
    lohngruppe      varchar2(10 char),
    vertragsart     number(3, 0),
    vertragsart_tx  varchar2(20 char),
    kennz_zeiterf   number(1, 0),
    schnittstelle   number(1, 0),
    personalteilber varchar2(15 char),
    eintrittsdatum  date,
    austrittdatum   date,
    azubi           number(1, 0) default 0,
    sm_name         varchar2(100 char),
    sm_beginn       date,
    akt_sa_name     varchar2(100 char),
    befristet_bis   date,
    ustd_freistd    varchar2(10 char) default 'AZ',
    max_freistd     number(*, 12) default 20,
    zk_von1_freistd number(*, 12),
    zk_bis1_freistd number(*, 12),
    zk_von2_freistd number(*, 12),
    zk_bis2_freistd number(*, 12)
);

alter table dirkspzm32.s_pzm_pers add constraint u_s_pzm_pers_pers_nr unique ( pers_nr )
    using index enable;

alter table dirkspzm32.s_pzm_pers add constraint u_s_pzm_pers_username unique ( username )
    using index enable;


